def validate(args, output):
    row_sum, col_sum = args
    m, n = len(row_sum), len(col_sum)
    if not isinstance(output, list) or len(output) != m:
        return False
    for row in output:
        if not isinstance(row, list) or len(row) != n:
            return False
        for v in row:
            if not isinstance(v, int) or isinstance(v, bool) or v < 0:
                return False
    for i in range(m):
        if sum(output[i]) != row_sum[i]:
            return False
    for j in range(n):
        if sum(output[i][j] for i in range(m)) != col_sum[j]:
            return False
    return True

