function validate(args, output) {
    const [rowSum, colSum] = args;
    const m = rowSum.length, n = colSum.length;
    if (!Array.isArray(output) || output.length !== m) return false;
    for (const row of output) {
        if (!Array.isArray(row) || row.length !== n) return false;
        for (const v of row) {
            if (typeof v !== 'number' || !Number.isInteger(v) || v < 0) return false;
        }
    }
    for (let i = 0; i < m; i++) {
        const s = output[i].reduce((a, b) => a + b, 0);
        if (s !== rowSum[i]) return false;
    }
    for (let j = 0; j < n; j++) {
        let s = 0;
        for (let i = 0; i < m; i++) s += output[i][j];
        if (s !== colSum[j]) return false;
    }
    return true;
}

