class Solution:
    def restoreMatrix(self, rowSum, colSum):
        m, n = len(rowSum), len(colSum)
        mat = [[0] * n for _ in range(m)]
        rs = rowSum[:]
        cs = colSum[:]
        for i in range(m):
            for j in range(n):
                v = min(rs[i], cs[j])
                mat[i][j] = v
                rs[i] -= v
                cs[j] -= v
        return mat

