var restoreMatrix = function(rowSum, colSum) {
    const m = rowSum.length, n = colSum.length;
    const mat = Array.from({length: m}, () => new Array(n).fill(0));
    const rs = rowSum.slice();
    const cs = colSum.slice();
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            const v = Math.min(rs[i], cs[j]);
            mat[i][j] = v;
            rs[i] -= v;
            cs[j] -= v;
        }
    }
    return mat;
};
